660	    pub fn new_lib(
661	        &mut self,
662	        funcs: &[(&[u8], LuaCFunction)],
663	    ) -> Result<(), LuaError> {
664	        create_table(self, 0, funcs.len() as i32)?;
665	        for (name, f) in funcs {
666	            push_cclosure(self, *f, 0)?;
667	            set_field(self, -2, name)?;
668	        }
669	        Ok(())
670	    }
671	
672	    /// Create and populate a library table for `funcs`, leaving it on top of
673	    /// the stack. The `_name` argument is informational and matches the
674	    /// `luaL_register`-style call sites in the Phase-A stdlib; the actual
675	    /// global binding for the library happens later via `luaL_requiref`.
676	    ///
677	    /// C: `luaL_newlib(L, l)`.
678	    pub fn register_lib(
679	        &mut self,
680	        _name: &[u8],
681	        funcs: &[(&[u8], LuaCFunction)],
682	    ) -> Result<(), LuaError> {
683	        self.new_lib(funcs)
684	    }
685	
686	    /// Create a new empty table presized to hold every entry in `funcs`, and
687	    /// leave it on top of the stack. No registration is performed — callers
688	    /// typically follow up with `set_funcs` / `set_funcs_with_upvalues` to
689	    /// populate the table.
690	    ///
691	    /// C: `luaL_newlibtable(L, l)` =
692	    ///   `lua_createtable(L, 0, sizeof(l)/sizeof((l)[0]) - 1)`. The C macro's
693	    /// `- 1` discounts the sentinel `{NULL, NULL}` entry; the Rust slice has
694	    /// no sentinel, so we use `funcs.len()` directly.
695	    pub fn new_lib_table(
696	        &mut self,
697	        funcs: &[(&[u8], LuaCFunction)],
698	    ) -> Result<(), LuaError> {
699	        create_table(self, 0, funcs.len() as i32)
700	    }
701	
702	    /// Register each entry in `funcs` as a C closure on the table at index
703	    /// `-(nup + 2)`, sharing the `nup` values currently on top of the stack
704	    /// as upvalues. The upvalues are popped at the end.
705	    ///
706	    /// C: `luaL_setfuncs(L, l, nup)`.
707	    pub fn set_funcs_with_upvalues(
708	        &mut self,
709	        funcs: &[(&[u8], LuaCFunction)],
710	        nup: i32,
711	    ) -> Result<(), LuaError> {
712	        check_stack(self, nup);
